package de.tum.cit.aet.artemis.iris.domain.message;

/**
 * This enum represents the different senders of Iris messages.
 * <p>
 * USER: A message sent by a user of the system
 * <p>
 * LLM: A message generated by a large language model
 * <p>
 * ARTIFACT: A artifact generated by the system, such as a tutor suggestion
 * <p>
 * COMMAND: A system-generated marker recording an action Iris performed on the client
 * (e.g. pointing the student to a slide page / video timestamp in the combined view).
 * It carries no LLM or user text; its content is an {@link IrisJsonMessageContent}
 * describing the action, rendered by the client as a clickable navigation marker.
 * <p>
 * Note: The ARTEMIS message sender variant was removed, as its original intent was
 * based on an incomplete understanding of the requirements of the Iris subsystem.
 */
public enum IrisMessageSender {
    USER, LLM, ARTIFACT, COMMAND
}
